if (Feed.newFeedItem.FeedTitle !== 'Cucina') {
  Dropbox.addFileFromUrl.skip();
} else {
  const title = Feed.newFeedItem.EntryTitle;
  const imageUrl = Feed.newFeedItem.EntryImageUrl;
  const published = Feed.newFeedItem.EntryPublished;
  const content = Feed.newFeedItem.EntryContent;

  // Extract tags from entry title
  let tagMatch = title.match(/(\bPrimi\b|\bSecondi\b|\bAntipasti\b)/);
  if (!tagMatch) {
    Dropbox.addFileFromUrl.skip();
  } else {
    const tag = tagMatch[0].toLowerCase();

    // Create text file with entry title and image URL
    Dropbox.createTextFileDb.setPath(`/${tag}`);
    Dropbox.createTextFileDb.setFilename('entry.txt');
    const body = `Title: ${title}\nImage URL: ${imageUrl}\nPublished: ${published}\nContent:\n${content}`;
    Dropbox.createTextFileDb.setBody(body);

    // Add image file to same path with title as filename
    const filename = title.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    Dropbox.addFileFromUrl.setPath(`/${tag}`);
    Dropbox.addFileFromUrl.setFilename(filename);
    Dropbox.addFileFromUrl.setUrl(imageUrl);
  }
}

